import sys

baseline = {}
with open('bench_all_2.txt') as f:
    for line in f:
        parts = line.split()
        if len(parts) >= 4 and parts[0] not in ('function', '--------', 'Done.'):
            baseline[parts[0]] = (int(parts[1]), int(parts[2]))

newdata = {}
with open('bench_after_latency.txt') as f:
    for line in f:
        parts = line.split()
        if len(parts) >= 4 and parts[0] not in ('function', '--------', 'Done.'):
            newdata[parts[0]] = (int(parts[1]), int(parts[2]))

print(f'{'func':<14} {'base_opt':>9} {'new_opt':>9} {'delta':>9} {'%':>7}')
print('-'*52)
for fn in baseline:
    if fn in newdata:
        b = baseline[fn][1]
        n = newdata[fn][1]
        d = n - b
        pct = 100*d/b
        if abs(pct) >= 0.5:
            marker = ' <-- REGRESSION' if pct > 1.0 else ''
            print(f'{fn:<14} {b:>9} {n:>9} {d:>+9} {pct:>6.1f}%{marker}')
